3832 std::tuple<Value *, FPClassTest, FPClassTest>
3833 llvm::fcmpImpliesClass(CmpInst::Predicate Pred, const Function &F, Value *LHS,
3834                        FPClassTest RHSClass, bool LookThroughSrc) {
3835   assert(RHSClass != fcNone);
3836 
3837   const FPClassTest OrigClass = RHSClass;
3838 
3839   Value *Src = LHS;
3840   const bool IsNegativeRHS = (RHSClass & fcNegative) == RHSClass;
3841   const bool IsPositiveRHS = (RHSClass & fcPositive) == RHSClass;
3842   const bool IsNaN = (RHSClass & ~fcNan) == fcNone;
3843 
3844   if (IsNaN) {
3845     // fcmp o__ x, nan -> false
3846     // fcmp u__ x, nan -> true
3847     return exactClass(Src, CmpInst::isOrdered(Pred) ? fcNone : fcAllFlags);
3848   }
3849 
3850   // fcmp ord x, zero|normal|subnormal|inf -> ~fcNan
3851   if (Pred == FCmpInst::FCMP_ORD)
3852     return exactClass(Src, ~fcNan);
3853 
3854   // fcmp uno x, zero|normal|subnormal|inf -> fcNan
3855   if (Pred == FCmpInst::FCMP_UNO)
3856     return exactClass(Src, fcNan);
3857 
3858   if (Pred == FCmpInst::FCMP_TRUE)
3859     return exactClass(Src, fcAllFlags);
3860 
3861   if (Pred == FCmpInst::FCMP_FALSE)
3862     return exactClass(Src, fcNone);
3863 
3864   const bool IsFabs = LookThroughSrc && match(LHS, m_FAbs(m_Value(Src)));
