3872     // are not flushed.
3873     // TODO: Handle DAZ by expanding masks to cover subnormal cases.
3874     if (!inputDenormalIsIEEE(F, LHS->getType()))
3875       return {nullptr, fcAllFlags, fcAllFlags};
