3877     switch (Pred) {
3878     case FCmpInst::FCMP_OEQ: // Match x == 0.0
3879       return exactClass(Src, fcZero);
3880     case FCmpInst::FCMP_UEQ: // Match isnan(x) || (x == 0.0)
3881       return exactClass(Src, fcZero | fcNan);
3882     case FCmpInst::FCMP_UNE: // Match (x != 0.0)
3883       return exactClass(Src, ~fcZero);
3884     case FCmpInst::FCMP_ONE: // Match !isnan(x) && x != 0.0
